void categorizeNumbers(const vector<int>& numbers) {
    cout << "EVEN NUMBERS:" << endl;
    for (int num : numbers) {
        if (num % 2 == 0) {
            cout << num << endl;
        }
    }

    cout << "ODD NUMBERS:" << endl;
